INSERT INTO `blog_comments` (`id`, `blog_id`, `commenter_user_id`, `comment_text`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1,	1,	3,	'This gives tutors a clear place to share updates with students.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(2,	1,	4,	'A central place for announcements will help a lot during busy weeks.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(3,	2,	5,	'The reflection step is useful because it shows what I still need to revise.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(4,	3,	2,	'This is the kind of student perspective we should encourage more often.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(5,	4,	6,	'Bringing one paragraph draft into the session made feedback much easier to act on.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(6,	4,	12,	'The rubric idea is useful because it keeps the discussion tied to marking criteria.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(7,	5,	15,	'Short checkpoints work well for me because I can see what is still weak each week.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(8,	5,	8,	'I use a similar structure in programming modules and it improves attendance too.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(9,	6,	9,	'Input validation is still one of the easiest quality wins for student teams.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(10,	6,	16,	'A checklist for submission week would help because those issues are easy to miss under time pressure.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(11,	7,	10,	'That kind of small daily routine is usually easier to sustain than last-minute cramming.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(12,	8,	17,	'We tried this last week and the session stayed much more focused.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL);
INSERT INTO `blogs` (`id`, `author_user_id`, `title`, `content`, `cover_image_path`, `hashtags`, `is_active`, `view_count`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1,	2,	'Welcome to the Greenwich tutoring hub',	'<p>Use this space to share updates, study guidance, and practical reminders with tutors and students.</p>',	'blog-covers/4k4B4q7V1QyT8yOqZ7KttcOvJvkwvx0UPLF1Cpdv.jpg',	'[\"community\", \"greenwich\"]',	1,	18,	'2026-04-05 07:19:52',	'2026-04-08 18:04:25',	NULL),
(2,	3,	'How I plan weekly tutoring sessions',	'<p>I break each session into revision, guided practice, and a short reflection so the student leaves with a clear next step.</p>',	'blog-covers/JKlA2inaPAiSW1mmu1q1hLht4CWRFVbAND6QDpUT.jpg',	'[\"tutoring\", \"planning\"]',	1,	12,	'2026-04-05 07:19:52',	'2026-04-08 18:04:16',	NULL),
(3,	4,	'Study habits that helped me improve',	'<p>Keeping one concise notebook and reviewing after each session made it much easier to track what still needed work.</p>',	'blog-covers/6HYMIeGzD9gOrKN9BEMsmpSPA80eCerbNNP4HrAr.jpg',	'[\"study\", \"reflection\"]',	0,	7,	'2026-04-05 07:19:52',	'2026-04-08 18:04:08',	NULL),
(4,	8,	'Making one-to-one writing support more practical',	'<p>I now ask students to bring one paragraph draft, one marking rubric, and one question. That keeps each session focused and measurable.</p>',	'blog-covers/zdVS21mCI1ov3GSRiw1Fpm7yG90KwyOvC7CfqHJc.jpg',	'[\"writing\", \"support\"]',	1,	26,	'2026-04-05 07:19:52',	'2026-04-08 18:03:56',	NULL),
(5,	9,	'Revision checkpoints for data-heavy modules',	'<p>Students usually improve faster when revision is broken into short weekly checkpoints instead of one large catch-up session.</p>',	'blog-covers/2b5RNlRBSp4eY7u0QlFetJzIVIFhDzkWWtKgZhog.png',	'[\"revision\", \"data\"]',	1,	21,	'2026-04-05 07:19:52',	'2026-04-08 18:03:48',	NULL),
(6,	10,	'Common security mistakes I see in student projects',	'<p>Hard-coded secrets, missing input validation, and weak password handling still appear regularly. They are good teaching moments because the fixes are concrete.</p>',	'blog-covers/dH1RsOWvkfoSsmELwxf3UtvbnVBGe8SwFUafydJU.jpg',	'[\"security\", \"projects\"]',	1,	31,	'2026-04-05 07:19:52',	'2026-04-08 18:03:34',	NULL),
(7,	5,	'What helped me stay consistent before exams',	'<p>A short daily review block worked better for me than long weekend study sessions. It reduced panic and made tutorials easier to follow.</p>',	'blog-covers/T07Z1fcQXw5yHbLYlsBO703BFUCrFbVEA2KcZEZv.jpg',	'[\"exams\", \"routine\"]',	1,	15,	'2026-04-05 07:19:52',	'2026-04-08 18:03:22',	NULL),
(8,	6,	'Group revision is useful when everyone brings a question',	'<p>Our study group improved once everyone arrived with one question and one worked example. It stopped the sessions from drifting.</p>',	'blog-covers/0YbX34mR5SBniRQdY5mMlFcFwZ2HetV2L95HVs46.jpg',	'[\"groupstudy\", \"revision\"]',	1,	13,	'2026-04-05 07:19:52',	'2026-04-08 18:03:08',	NULL),
(9,	1,	'What is Computer Science ?',	'<p>What is Computer Science?</p>',	'blog-covers/fDwVRyUv6DIXSGkZmcGUJPQlWKcCfjC445aPsGkl.jpg',	'[\"computer\", \"science\"]',	1,	11,	'2026-04-05 09:44:25',	'2026-04-09 15:27:05',	NULL);
