INSERT INTO `messages` (`id`, `conversation_id`, `sender_user_id`, `content`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1,	1,	NULL,	'Welcome! This conversation has been created for your tutor assignment. Feel free to introduce yourselves and plan your first session.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(2,	1,	3,	'I have mapped out our February to May computer science tutoring plan so each week builds toward the mock practical.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(3,	1,	4,	'That helps a lot. The weekly structure makes the programming topics feel much more manageable.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(4,	1,	3,	'Please keep sending your code before each Wednesday session so I can tailor the debugging examples.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(5,	1,	4,	'I sent the control-flow and function exercises from last week. Recursion is still the hardest topic for me.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(6,	1,	3,	'I reviewed them. We will spend the first half of the next meeting on recursion and then move into timed coding practice.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(7,	1,	4,	'Sounds good. I also wanted to ask whether we can revisit the cancelled recursion workshop with a new exercise sheet.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(8,	1,	3,	'Yes. I added a replacement problem set and folded the missed material into our next two meetings.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(9,	1,	4,	'Thank you. The feedback on my mock quiz was useful even though I was on leave for that session.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(10,	1,	3,	'Before the upcoming meeting, complete the searching and sorting tasks and flag any bugs you want to review live.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(11,	1,	4,	'I will finish them tonight and upload the files before tomorrow afternoon.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(12,	2,	2,	'Please share your weekly tutoring update this afternoon.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(13,	2,	3,	'Understood. I will include attendance and progress notes.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(14,	2,	2,	'Thanks. Please flag any students who may need extra support.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(15,	3,	8,	'Hi, let us focus on the key topics for this week.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
(16,	3,	5,	'That works for me. I still need help with the last exercise set.',	'2026-04-05 07:19:52',	'2026-04-05 07:19:52',	NULL),
